index fc284bc61cce..9f2e52d018a6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1134,7 +1134,7 @@ static bool MulWillOverflow(APInt &C0, APInt &C1, bool IsSigned) {

 // Simplifies X % C0 + (( X / C0 ) % C1) * C0 to X % (C0 * C1), where (C0 * C1)
 // does not overflow.
-Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
+Value *InstCombinerImpl::SimplifyAddWithRemainder(Instruction &I) {
   Value *LHS = I.getOperand(0), *RHS = I.getOperand(1);
   Value *X, *MulOpV;
   APInt C0, MulOpC;
@@ -1161,6 +1161,24 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
     }
   }

+  // Match I = X % C0 + (X / C0) * C1
+  // If C1 > C0, fold to (X / C0) * (C1 - C0) + X
+  if (((MatchRem(LHS, X, C0, IsSigned) && MatchMul(RHS, MulOpV, MulOpC)) ||
+       (MatchRem(RHS, X, C0, IsSigned) && MatchMul(LHS, MulOpV, MulOpC)))) {
+    Value *DivOpV;
+    APInt DivOpC;
+    if (MatchDiv(MulOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
+        C0 == DivOpC) {
+      if (MulOpC.ugt(C0)) {
+        Value *Div = MulOpV;
+        Value *NewMul = Builder.CreateMul(Div, ConstantInt::get(X->getType(), MulOpC - C0), "reass.mul");
+        if (!IsSigned)
+          if (auto *NewMulInst = dyn_cast<Instruction>(NewMul))
+            NewMulInst->setHasNoUnsignedWrap();
+        return Builder.CreateAdd(NewMul, X);
+      }
+    }
+  }
   return nullptr;
 }

